my @allowed_hosts = (
    'www.example.com',
    'app.example.com',
    'example.com',
);

my $default_url = '/dashboard';

sub is_safe_redirect {
    my ($url) = @_;

    return 0 unless defined $url;
    return 0 if $url eq '';

    # Block javascript:, data:, vbscript: schemes
    if ($url =~ /^\s*(javascript|data|vbscript)\s*:/i) {
        return 0;
    }

    # Block protocol-relative URLs (e.g., //evil.com)
    if ($url =~ /^\/\//) {
        return 0;
    }

    # Allow relative URLs starting with /
    if ($url =~ /^\/[^\/]/ || $url eq '/') {
        # Prevent header injection by blocking newlines/carriage returns
        if ($url =~ /[\r\n]/) {
            return 0;
        }
        return 1;
    }

    # For absolute URLs, validate against allowed hosts
    my $uri = eval { URI->new($url) };
    return 0 unless $uri;

    my $scheme = $uri->scheme // '';
    return 0 unless $scheme =~ /^https?$/i;

    my $host = $uri->host // '';
    $host = lc($host);

    foreach my $allowed (@allowed_hosts) {
        if ($host eq lc($allowed)) {
            # Prevent header injection
            if ($url =~ /[\r\n]/) {
                return 0;
            }
            return 1;
        }
    }

    return 0;
}

sub sanitize_url {
    my ($url) = @_;

    # Strip any CR/LF characters to prevent HTTP header injection
    $url =~ s/[\r\n]//g;

    # Decode any percent-encoded CR/LF
    $url =~ s/%0[aAdD]//gi;

